import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Check input length before copying to buffer
        if (input.length() > 10) {
            System.out.println("Input string is too long. Please enter a string with length <= 10 characters.");
            return;
        }

        char[] buffer = new char[10];
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Input successfully copied to buffer.");
    }
}

### Explanation:
취약유형: Buffer Overflow
